pragma solidity ^0.5.4;

import "openzeppelin-solidity/contracts/math/SafeMath.sol";
import "openzeppelin-solidity/contracts/utils/ReentrancyGuard.sol";
import "./TokenStaking.sol";
import "./cryptography/BLS.sol";
import "./utils/AddressArrayUtils.sol";
import "./libraries/operator/GroupSelection.sol";
import "./libraries/operator/Groups.sol";
import "./libraries/operator/DKGResultVerification.sol";
import "./libraries/operator/Reimbursements.sol";

interface ServiceContract {
    function entryCreated(uint256 requestId, bytes calldata entry, address payable submitter) external;
    function fundRequestSubsidyFeePool() external payable;
    function fundDkgFeePool() external payable;
}


contract KeepRandomBeaconOperator is ReentrancyGuard {
    using SafeMath for uint256;
    using AddressArrayUtils for address[];
    using GroupSelection for GroupSelection.Storage;
    using Groups for Groups.Storage;
    using DKGResultVerification for DKGResultVerification.Storage;

    event OnGroupRegistered(bytes groupPubKey);



    event DkgResultPublishedEvent(bytes groupPubKey);

    event RelayEntryRequested(bytes previousEntry, bytes groupPublicKey);
    event RelayEntrySubmitted();

    event GroupSelectionStarted(uint256 newEntry);

    event GroupMemberRewardsWithdrawn(address indexed beneficiary, address operator, uint256 amount, uint256 groupIndex);

    GroupSelection.Storage groupSelection;
    Groups.Storage groups;
    DKGResultVerification.Storage dkgResultVerification;


    address internal owner;

    address[] internal serviceContracts;


    TokenStaking internal stakingContract;



    uint256 public minimumStake = 200000 * 1e18;


    uint256 public groupMemberBaseReward = 145*1e11; 





    uint256 public priceFeedEstimate = 20*1e9; 



    uint256 public fluctuationMargin = 50; 


    uint256 public groupSize = 64;



    uint256 public groupThreshold = 33;



    uint256 public resultPublicationBlockStep = 3;



    uint256 public relayEntryGenerationTime = (1+3);







    uint256 public relayEntryTimeout = relayEntryGenerationTime.add(groupSize.mul(resultPublicationBlockStep));




    uint256 public entryVerificationGasEstimate = 280000;


    uint256 public dkgGasEstimate = 1740000;


    uint256 public groupSelectionGasEstimate = 100000;







    uint256 public dkgSubmitterReimbursementFee;


    ServiceContract internal groupSelectionStarterContract;

    struct SigningRequest {
        uint256 relayRequestId;
        uint256 entryVerificationAndProfitFee;
        uint256 callbackFee;
        uint256 groupIndex;
        bytes previousEntry;
        address serviceContract;
    }

    uint256 internal currentEntryStartBlock;
    SigningRequest internal signingRequest;



    uint256 internal _genesisGroupSeed = 31415926535897932384626433832795028841971693993751058209749445923078164062862;


    function genesis() public payable {
        require(numberOfGroups() == 0, "Groups exist");

        groupSelectionStarterContract = ServiceContract(serviceContracts[serviceContracts.length.sub(1)]);
        startGroupSelection(_genesisGroupSeed, msg.value);
    }


    modifier onlyOwner() {
        require(owner == msg.sender, "Caller is not the owner");
        _;
    }


    modifier onlyServiceContract() {
        require(
            serviceContracts.contains(msg.sender),
            "Caller is not an authorized contract"
        );
        _;
    }

    constructor(address _serviceContract, address _stakingContract) public {
        owner = msg.sender;

        serviceContracts.push(_serviceContract);
        stakingContract = TokenStaking(_stakingContract);

        groups.stakingContract = TokenStaking(_stakingContract);
        groups.groupActiveTime = TokenStaking(_stakingContract).undelegationPeriod();

        groupSelection.ticketSubmissionTimeout = 12;
        groupSelection.groupSize = groupSize;

        dkgResultVerification.timeDKG = 5*(1+5) + 2*(1+10);
        dkgResultVerification.resultPublicationBlockStep = resultPublicationBlockStep;
        dkgResultVerification.groupSize = groupSize;



        dkgResultVerification.signatureThreshold = groupThreshold;
    }


    function addServiceContract(address serviceContract) public onlyOwner {
        serviceContracts.push(serviceContract);
    }


    function removeServiceContract(address serviceContract) public onlyOwner {
        serviceContracts.removeAddress(serviceContract);
    }


    function setPriceFeedEstimate(uint256 _priceFeedEstimate) public onlyOwner {
        priceFeedEstimate = _priceFeedEstimate;
    }


    function gasPriceWithFluctuationMargin(uint256 gasPrice) internal view returns (uint256) {
        return gasPrice.add(gasPrice.mul(fluctuationMargin).div(100));
    }


    function createGroup(uint256 _newEntry, address payable submitter) public payable onlyServiceContract {
        uint256 groupSelectionStartFee = groupSelectionGasEstimate
            .mul(gasPriceWithFluctuationMargin(priceFeedEstimate));

        groupSelectionStarterContract = ServiceContract(msg.sender);
        startGroupSelection(_newEntry, msg.value.sub(groupSelectionStartFee));


        (bool success, ) = stakingContract.magpieOf(submitter).call.value(groupSelectionStartFee)("");
        require(success, "Failed reimbursing submitter for starting a group selection");
    }

    function startGroupSelection(uint256 _newEntry, uint256 _payment) internal {
        require(
            _payment >= gasPriceWithFluctuationMargin(priceFeedEstimate).mul(dkgGasEstimate),
            "Insufficient DKG fee"
        );

        require(isGroupSelectionPossible(), "Group selection in progress");



        if (dkgSubmitterReimbursementFee > 0) {
            uint256 surplus = dkgSubmitterReimbursementFee;
            dkgSubmitterReimbursementFee = 0;
            ServiceContract(msg.sender).fundDkgFeePool.value(surplus)();
        }

        groupSelection.start(_newEntry);
        emit GroupSelectionStarted(_newEntry);
        dkgSubmitterReimbursementFee = _payment;
    }

    function isGroupSelectionPossible() public view returns (bool) {
        if (!groupSelection.inProgress) {
            return true;
        }



        uint256 dkgTimeout = groupSelection.ticketSubmissionStartBlock +
        groupSelection.ticketSubmissionTimeout +
        dkgResultVerification.timeDKG +
        groupSize * resultPublicationBlockStep;

        return block.number > dkgTimeout;
    }


    function submitTicket(bytes32 ticket) public {
        uint256 stakingWeight = stakingContract.eligibleStake(msg.sender, address(this)).div(minimumStake);
        groupSelection.submitTicket(ticket, stakingWeight);
    }


    function ticketSubmissionTimeout() public view returns (uint256) {
        return groupSelection.ticketSubmissionTimeout;
    }


    function submittedTicketsCount() public view returns (uint256) {
        return groupSelection.tickets.length;
    }


    function selectedParticipants() public view returns (address[] memory) {
        return groupSelection.selectedParticipants();
    }


    function submitDkgResult(
        uint256 submitterMemberIndex,
        bytes memory groupPubKey,
        bytes memory misbehaved,
        bytes memory signatures,
        uint[] memory signingMembersIndexes
    ) public {
        address[] memory members = selectedParticipants();

        dkgResultVerification.verify(
            submitterMemberIndex,
            groupPubKey,
            misbehaved,
            signatures,
            signingMembersIndexes,
            members,
            groupSelection.ticketSubmissionStartBlock + groupSelection.ticketSubmissionTimeout
        );

        groups.setGroupMembers(groupPubKey, members, misbehaved);
        groups.addGroup(groupPubKey);
        reimburseDkgSubmitter();
        emit DkgResultPublishedEvent(groupPubKey);
        groupSelection.stop();
    }


    function reimburseDkgSubmitter() internal {
        uint256 gasPrice = priceFeedEstimate;



        if (tx.gasprice > 0 && tx.gasprice < priceFeedEstimate) {
            gasPrice = tx.gasprice;
        }

        uint256 reimbursementFee = dkgGasEstimate.mul(gasPrice);
        address payable magpie = stakingContract.magpieOf(msg.sender);

        if (reimbursementFee < dkgSubmitterReimbursementFee) {
            uint256 surplus = dkgSubmitterReimbursementFee.sub(reimbursementFee);
            dkgSubmitterReimbursementFee = 0;

            magpie.call.value(reimbursementFee)("");


            groupSelectionStarterContract.fundDkgFeePool.value(surplus)();
        } else {

            reimbursementFee = dkgSubmitterReimbursementFee;
            dkgSubmitterReimbursementFee = 0;
            magpie.call.value(reimbursementFee)("");
        }
    }


    function setMinimumStake(uint256 _minimumStake) public onlyOwner {
        minimumStake = _minimumStake;
    }


    function sign(
        uint256 requestId,
        bytes memory previousEntry
    ) public payable onlyServiceContract {
        uint256 entryVerificationAndProfitFee = groupProfitFee().add(
            entryVerificationGasEstimate.mul(gasPriceWithFluctuationMargin(priceFeedEstimate))
        );
        require(
            msg.value >= entryVerificationAndProfitFee,
            "Insufficient new entry fee"
        );
        uint256 callbackFee = msg.value.sub(entryVerificationAndProfitFee);
        signRelayEntry(
            requestId, previousEntry, msg.sender,
            entryVerificationAndProfitFee, callbackFee
        );
    }

    function signRelayEntry(
        uint256 requestId,
        bytes memory previousEntry,
        address serviceContract,
        uint256 entryVerificationAndProfitFee,
        uint256 callbackFee
    ) internal {
        require(!isEntryInProgress() || hasEntryTimedOut(), "Beacon is busy");

        currentEntryStartBlock = block.number;

        uint256 groupIndex = groups.selectGroup(uint256(keccak256(previousEntry)));
        signingRequest = SigningRequest(
            requestId,
            entryVerificationAndProfitFee,
            callbackFee,
            groupIndex,
            previousEntry,
            serviceContract
        );

        bytes memory groupPubKey = groups.getGroupPublicKey(groupIndex);
        emit RelayEntryRequested(previousEntry, groupPubKey);
    }



    function relayEntry(bytes memory _groupSignature) public nonReentrant {
        require(isEntryInProgress(), "Entry was submitted");
        require(!hasEntryTimedOut(), "Entry timed out");

        bytes memory groupPubKey = groups.getGroupPublicKey(signingRequest.groupIndex);

        require(
            BLS.verify(
                groupPubKey,
                signingRequest.previousEntry,
                _groupSignature
            ),
            "Invalid signature"
        );

        emit RelayEntrySubmitted();



        signingRequest.serviceContract.call.gas(groupSelectionGasEstimate.add(40000))(
            abi.encodeWithSignature(
                "entryCreated(uint256,bytes,address)",
                signingRequest.relayRequestId,
                _groupSignature,
                msg.sender
            )
        );

        if (signingRequest.callbackFee > 0) {
            executeCallback(signingRequest, uint256(keccak256(_groupSignature)));
        }

        (uint256 groupMemberReward, uint256 submitterReward, uint256 subsidy) = newEntryRewardsBreakdown();
        groups.addGroupMemberReward(groupPubKey, groupMemberReward);

        stakingContract.magpieOf(msg.sender).call.value(submitterReward)("");

        if (subsidy > 0) {
            signingRequest.serviceContract.call.gas(35000).value(subsidy)(abi.encodeWithSignature("fundRequestSubsidyFeePool()"));
        }

        currentEntryStartBlock = 0;
    }


    function executeCallback(SigningRequest memory signingRequest, uint256 entry) internal {
        uint256 callbackFee = signingRequest.callbackFee;


        uint256 gasLimit = callbackFee.div(gasPriceWithFluctuationMargin(priceFeedEstimate));

        bytes memory callbackReturnData;
        uint256 gasBeforeCallback = gasleft();
        (, callbackReturnData) = signingRequest.serviceContract.call.gas(gasLimit)(abi.encodeWithSignature("executeCallback(uint256,uint256)", signingRequest.relayRequestId, entry));
        uint256 gasAfterCallback = gasleft();
        uint256 gasSpent = gasBeforeCallback.sub(gasAfterCallback);

        Reimbursements.reimburseCallback(
            stakingContract,
            priceFeedEstimate,
            gasLimit,
            gasSpent,
            callbackFee,
            callbackReturnData
        );
    }


    function newEntryRewardsBreakdown() internal view returns(uint256 groupMemberReward, uint256 submitterReward, uint256 subsidy) {
        uint256 decimals = 1e16; 

        uint256 delayFactor = getDelayFactor();
        groupMemberReward = groupMemberBaseReward.mul(delayFactor).div(decimals);


        uint256 groupMemberDelayPenalty = groupMemberBaseReward.mul(decimals.sub(delayFactor));






        uint256 submitterExtraReward = groupMemberDelayPenalty.mul(groupSize).mul(5).div(100).div(decimals);
        uint256 entryVerificationFee = signingRequest.entryVerificationAndProfitFee.sub(groupProfitFee());
        submitterReward = entryVerificationFee.add(submitterExtraReward);


        subsidy = groupProfitFee().sub(groupMemberReward.mul(groupSize)).sub(submitterExtraReward);
    }


    function getDelayFactor() internal view returns(uint256 delayFactor) {
        uint256 decimals = 1e16; 






        uint256 deadlineBlock = currentEntryStartBlock.add(relayEntryTimeout).add(1);




        uint256 submissionStartBlock = currentEntryStartBlock.add(relayEntryGenerationTime).add(1);


        uint256 entryReceivedBlock = block.number <= submissionStartBlock ? submissionStartBlock:block.number;


        uint256 remainingBlocks = deadlineBlock.sub(entryReceivedBlock);


        uint256 submissionWindow = deadlineBlock.sub(submissionStartBlock);






        delayFactor = ((remainingBlocks.mul(decimals).div(submissionWindow))**2).div(decimals);
    }


    function isEntryInProgress() internal view returns (bool) {
        return currentEntryStartBlock != 0;
    }


    function hasEntryTimedOut() internal view returns (bool) {
        return currentEntryStartBlock != 0 && block.number > currentEntryStartBlock + relayEntryTimeout;
    }


    function reportRelayEntryTimeout() public {
        require(hasEntryTimedOut(), "Entry did not time out");
        groups.reportRelayEntryTimeout(signingRequest.groupIndex, groupSize, minimumStake);




        if (numberOfGroups() > 0) {
            signRelayEntry(
                signingRequest.relayRequestId,
                signingRequest.previousEntry,
                signingRequest.serviceContract,
                signingRequest.entryVerificationAndProfitFee,
                signingRequest.callbackFee
            );
        }
    }


    function groupProfitFee() public view returns(uint256) {
        return groupMemberBaseReward.mul(groupSize);
    }


    function hasMinimumStake(address staker) public view returns(bool) {
        return (
            stakingContract.activeStake(staker, address(this)) >= minimumStake
        );
    }


    function isGroupRegistered(bytes memory groupPubKey) public view returns(bool) {
        return groups.isGroupRegistered(groupPubKey);
    }


    function isStaleGroup(bytes memory groupPubKey) public view returns(bool) {
        return groups.isStaleGroup(groupPubKey);
    }


    function numberOfGroups() public view returns(uint256) {
        return groups.numberOfGroups();
    }


    function getGroupMemberRewards(bytes memory groupPubKey) public view returns (uint256) {
        return groups.groupMemberRewards[groupPubKey];
    }


    function getGroupMemberIndices(bytes memory groupPubKey, address member) public view returns (uint256[] memory indices) {
        return groups.getGroupMemberIndices(groupPubKey, member);
    }


    function withdrawGroupMemberRewards(address operator, uint256 groupIndex, uint256[] memory groupMemberIndices) public nonReentrant {
        uint256 accumulatedRewards = groups.withdrawFromGroup(operator, groupIndex, groupMemberIndices);
        (bool success, ) = stakingContract.magpieOf(operator).call.value(accumulatedRewards)("");
        if (success) {
            emit GroupMemberRewardsWithdrawn(stakingContract.magpieOf(operator), operator, accumulatedRewards, groupIndex);
        }
    }


    function getFirstActiveGroupIndex() public view returns (uint256) {
        return groups.expiredGroupOffset;
    }


    function getGroupPublicKey(uint256 groupIndex) public view returns (bytes memory) {
        return groups.getGroupPublicKey(groupIndex);
    }


    function groupCreationGasEstimate() public view returns (uint256) {
        return dkgGasEstimate.add(groupSelectionGasEstimate);
    }


    function getGroupMembers(bytes memory groupPubKey) public view returns (address[] memory members) {
        return groups.getGroupMembers(groupPubKey);
    }


    function reportUnauthorizedSigning(
        uint256 groupIndex,
        bytes memory signedGroupPubKey
    ) public {
        groups.reportUnauthorizedSigning(groupIndex, signedGroupPubKey, minimumStake);
    }
}

pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeCast.sol";

contract GreenHouse is Ownable {

    IERC20 public trustedToken;


    uint256 public allStakes = 0;
    uint256 public everStakedUsersCount = 0;


    uint256 public bonusRewardPool = 0;  
    uint256 public monthlyRewardPool = 0;  
    mapping(address => uint256) public referralRewards;


    mapping(address => uint256) internal _stakes;
    mapping(address => uint256) internal _withdrawals;
    mapping(address => bool) internal _hasStaked;


    uint256 constant internal MAGNITUDE = 2**128;

    uint256 internal _magnifiedRewardPerStake = 0;
    mapping(address => int256) internal _magnifiedRewardCorrections;


    uint256 constant internal FEE_ALL_USERS_STAKED_PERMILLE = 700;
    uint256 constant internal FEE_BONUS_POOL_PERMILLE = 100;
    uint256 constant internal FEE_PLATFORM_WALLET_PERMILLE = 100;
    uint256 constant internal TOKEN_DECIMAL=10**8;
    uint256 constant internal FEE_REFERRAL_PERMILLE = 50;
    uint256 constant internal FEE_PARTNER_WALLET_PERMILLE = 50;


    uint256 constant internal MONTHLY_POOL_DISTRIBUTE_ALL_USERS_PERCENT = 50;
    uint256 constant internal MONYHLY_POOL_TIMER = 86400; 
    uint256 internal _monthlyPoolLastDistributedAt=0;


    uint256 constant internal BONUS_POOL_DISTRIBUTE_ALL_USERS_PERCENT = 40;
    uint256 constant internal BONUS_POOL_DISTRIBUTE_LEADERBOARD_PERCENT = 40;


    mapping(uint256 => address) internal _bonusPoolLeaderboard;
    mapping(address => uint256) internal _bonusPoolLeaderboardPositionsCount;
    uint256 internal _bonusPoolLeaderboardFirst = 1;
    uint256 internal _bonusPoolLeaderboardLast = 0;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MAX_USERS_COUNT = 10;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_QUALIFY = 1000;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_MAINTAIN_POSITION = 900; 


uint256 internal _bonusPoolTimer;
uint256 internal _bonusPoolLastDistributedAt=0;
uint256 constant internal BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION = 900;   
    uint256 constant internal BONUS_POOL_TIMER_INITIAL = 21600; 


    address[] internal _platformWallets;

    address   internal _partnerWallet;

    event Staked(address indexed sender, uint256 amount, address indexed referrer);
    event Unstaked(address indexed sender, uint256 amount);
    event RewardWithdrawn(address indexed sender, uint256 amount);
    event BonusRewardPoolDistributed(uint256 amountAllUsers, uint256 amountLeaderboard);
    event MonthlyRewardPoolDistributed(uint256 amount);
    event Timer(uint256 timer);



    constructor(
        address trustedToken_,
        address partnerWallet,
        address[] memory platformWallets
    ) Ownable() {  

        trustedToken = IERC20(trustedToken_);
        _platformWallets = platformWallets;
        _partnerWallet = partnerWallet;
        _bonusPoolTimer = BONUS_POOL_TIMER_INITIAL;
    }

    modifier AttemptToDistrubuteBonusPools() {
        if(_bonusPoolLastDistributedAt == 0 && _monthlyPoolLastDistributedAt== 0){

            _bonusPoolLastDistributedAt = block.timestamp;

            _monthlyPoolLastDistributedAt = block.timestamp;
        }
        _maybeDistributeMonthlyRewardPool();
        _maybeDistributeBonusRewardPool();
        _;
    }



    function stake(uint256 amount, address referrer) external AttemptToDistrubuteBonusPools {
        amount=amount*TOKEN_DECIMAL;
        require(amount != 0, "GreenHouse: staking zero");
        require(
            trustedToken.transferFrom(msg.sender, address(this), amount),
            "GreenHouse: staking transfer"
        );
        require(msg.sender!=referrer,"GreenHouse: You cannot indicate yourself as a referral ");
        if(_stakes[referrer]<100*TOKEN_DECIMAL){
            referrer=address(0);
        }
        if (!_hasStaked[msg.sender]) {
            _hasStaked[msg.sender] = true;
            everStakedUsersCount++;
        }
        if (amount >= BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_QUALIFY*TOKEN_DECIMAL) {
            _bonusPoolProcessStakeholder(msg.sender);
        }

        _processStake(amount, referrer);
        emit Staked(msg.sender, amount, referrer);
    }

    function unstake(uint256 amount) external AttemptToDistrubuteBonusPools {
        amount=amount*TOKEN_DECIMAL;
        require(amount != 0, "GreenHouse: unstaking zero");
        require(_stakes[msg.sender] >= amount, "GreenHouse: unstake amount");

        (uint256 net, uint256 fee) = _applyFeesAndDistributeRewards(amount, address(0));
        _stakes[msg.sender] -= amount;
        _bonusPoolLeaderboardUnstakeToKick(msg.sender, _stakes[msg.sender]);


        _magnifiedRewardCorrections[msg.sender] += SafeCast.toInt256(_magnifiedRewardPerStake * amount);
        _rewardAllUsersStaked(fee);
        allStakes -= amount;

        require(
            trustedToken.transfer(msg.sender, net),
            "GreenHouse: unstake transfer"
        );

        emit Unstaked(msg.sender, amount);
    }

    function withdrawReward() external AttemptToDistrubuteBonusPools {
        uint256 withdrawable = withdrawableRewardOf(msg.sender);
        require(withdrawable > 0, "GreenHouse: nothing to withdraw");
        _withdrawals[msg.sender] += withdrawable;
        require(
            trustedToken.transfer(msg.sender, withdrawable),
            "GreenHouse: withdrawal transfer"
        );
        emit RewardWithdrawn(msg.sender, withdrawable);
    }

    function bonusPoolLeaderboard() external view returns(address[] memory) {
        uint256 leaderboardUsersCount = _bonusPoolLeaderboardUsersCount();
        address[] memory leaderboard = new address[](leaderboardUsersCount);
        uint256 ptr = 0;
        for (uint256 i = _bonusPoolLeaderboardFirst; i <= _bonusPoolLeaderboardLast; i++) {
            leaderboard[ptr] = _bonusPoolLeaderboard[i];
            ptr++;
        }
        return leaderboard;
    }


    function setPartnerWallet(address address_) external onlyOwner {
        _partnerWallet = address_;
    }

    function setPlatformWallets(address[] memory addresses) external onlyOwner {
        _platformWallets = addresses;
    }




    function stakeOf(address stakeholder) public view returns(uint256) {
        return _stakes[stakeholder];
    }

    function accumulativeRewardOf(address stakeholder) public view returns(uint256) {

        return SafeCast.toUint256(
            SafeCast.toInt256(
                stakeOf(stakeholder) * _magnifiedRewardPerStake
            ) + _magnifiedRewardCorrections[stakeholder]
        ) / MAGNITUDE;
    }

    function withdrawnRewardOf(address stakeholder) public view returns(uint256) {
        return _withdrawals[stakeholder];
    }

    function withdrawableRewardOf(address stakeholder) public view returns(uint256) {
        return accumulativeRewardOf(stakeholder) - withdrawnRewardOf(stakeholder);
    }

    function bonusRewardPoolCountdown() public view returns(uint256) {

        uint256 timeSinceLastDistributed = block.timestamp - _bonusPoolLastDistributedAt;
        if (timeSinceLastDistributed >= _bonusPoolTimer) return 0;
        return _bonusPoolTimer - timeSinceLastDistributed;
    }

    function monthlyRewardPoolCountdown() public view returns(uint256) {

        uint256 timeSinceLastDistributed = block.timestamp - _monthlyPoolLastDistributedAt;
        if (timeSinceLastDistributed >= MONYHLY_POOL_TIMER) return 0;
        return MONYHLY_POOL_TIMER - timeSinceLastDistributed;
    }



    function _bonusPoolLeaderboardPop() internal {
        address removed = _bonusPoolLeaderboard[_bonusPoolLeaderboardFirst];
        delete _bonusPoolLeaderboard[_bonusPoolLeaderboardFirst];
        _bonusPoolLeaderboardFirst++;
        _bonusPoolLeaderboardPositionsCount[removed]--;
        if (_bonusPoolLeaderboardPositionsCount[removed] == 0)
            delete _bonusPoolLeaderboardPositionsCount[removed];
    }

    function _bonusPoolLeaderboardPush(address value) internal {
        _bonusPoolLeaderboardLast++;
        _bonusPoolLeaderboard[_bonusPoolLeaderboardLast] = value;
        _bonusPoolLeaderboardPositionsCount[value] += 1;
        if((bonusRewardPoolCountdown()+BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION) >= BONUS_POOL_TIMER_INITIAL){
            _bonusPoolTimer += 0;
        }else{
        _bonusPoolTimer += BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION;
        }
        emit Timer(bonusRewardPoolCountdown()+BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION);
    }


    function _bonusPoolProcessStakeholder(address stakeholder) internal {
        _bonusPoolLeaderboardPush(stakeholder);

        if (_bonusPoolLeaderboardUsersCount() > BONUS_POOL_LEADERBOARD_MAX_USERS_COUNT)
            _bonusPoolLeaderboardPop();
    }

    function _bonusPoolLeaderboardKick(address stakeholder, uint256 positions) internal {

        uint256 positionsLeftToKick = positions;
        address[] memory leaderboard = new address[](_bonusPoolLeaderboardUsersCount() - positions);
        uint256 ptr = 0;
        for (
            uint256 i = _bonusPoolLeaderboardFirst;
            i <= _bonusPoolLeaderboardLast;
            i++
        ) {
            if (positionsLeftToKick > 0 && _bonusPoolLeaderboard[i] == stakeholder) {
                positionsLeftToKick--;
            } else {
                leaderboard[ptr] = _bonusPoolLeaderboard[i];
                ptr++;
            }

        }

        while (_bonusPoolLeaderboardUsersCount() > 0)
            _bonusPoolLeaderboardPop();
        for (uint256 i = 0; i < leaderboard.length; ++i)
            _bonusPoolLeaderboardPush(leaderboard[i]);
    }

    function _bonusPoolLeaderboardUnstakeToKick(address stakeholder, uint256 remaining) internal {
        uint256 maxPositions = remaining / BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_MAINTAIN_POSITION;
        if (maxPositions < _bonusPoolLeaderboardPositionsCount[stakeholder]) {
            uint256 positionsToKick = _bonusPoolLeaderboardPositionsCount[stakeholder] - maxPositions;
            _bonusPoolLeaderboardKick(stakeholder, positionsToKick);
        }
    }

    function _bonusPoolLeaderboardUsersCount() internal view returns(uint256) {
        return _bonusPoolLeaderboardLast + 1 - _bonusPoolLeaderboardFirst;
    }

    function _transferRewardPartner(uint256 amount) internal {
        require(
            trustedToken.transfer(_partnerWallet, amount),
            "GreenHouse: partner transfer"
        );
    }

    function _transferRewardPlatform(uint256 amount) internal {
        uint256 perWallet = amount / _platformWallets.length;
        for (uint256 i = 0; i != _platformWallets.length; ++i) {
            require(
                trustedToken.transfer(_platformWallets[i], perWallet),
                "GreenHouse: platform transfer"
            );
        }
    }

    function _rewardAllUsersStaked(uint256 amount) internal {
        _magnifiedRewardPerStake += allStakes != 0 ? (MAGNITUDE * amount) / allStakes : 0;
    }

    function _transferRewardReferral(uint256 amount, address referrer) internal {
        referralRewards[referrer] += amount;
        bool success = trustedToken.transfer(referrer, amount);
        require(success, "GreenHouse: referral transfer");
    }

    function _rewardBonusPool(uint256 amount) internal {
        bonusRewardPool += amount;
    }

    function _rewardMonthlyPool(uint256 amount) internal {
        monthlyRewardPool += amount;
    }

    function _calculateFees(uint256 amount)
    internal pure
    returns(
        uint256 allUsers,
        uint256 bonusPool,
        uint256 partner,
        uint256 referral,
        uint256 platform,
        uint256 net
    ) {
        allUsers = (amount * FEE_ALL_USERS_STAKED_PERMILLE) / 10000;
        bonusPool = (amount * FEE_BONUS_POOL_PERMILLE) / 10000;
        partner = (amount * FEE_PARTNER_WALLET_PERMILLE) / 10000;
        referral = (amount * FEE_REFERRAL_PERMILLE) / 10000;
        platform = (amount * FEE_PLATFORM_WALLET_PERMILLE) / 10000;
        net = amount - allUsers - bonusPool - partner - referral - platform;
    }

    function _applyFeesAndDistributeRewards(uint256 amount, address referrer)
        internal
        returns(uint256, uint256)
    {
        (
            uint256 fee,
            uint256 feeBonusPool,
            uint256 feePartnerWallet,
            uint256 feeReferral,
            uint256 feePlatformWallet,
            uint256 net
        ) = _calculateFees(amount);

        _rewardBonusPool(feeBonusPool);
        _transferRewardPartner(feePartnerWallet);
        _transferRewardPlatform(feePlatformWallet);

        if (referrer == address(0))
            _rewardMonthlyPool(feeReferral);
        else
            _transferRewardReferral(feeReferral, referrer);

        return (net, fee);
    }
    function _processStake(uint256 amount, address referrer) internal {
        (uint256 net, uint256 fee) = _applyFeesAndDistributeRewards(amount, referrer);
        _stakes[msg.sender] += net;

        allStakes += net;

        _magnifiedRewardCorrections[msg.sender] -= SafeCast.toInt256(_magnifiedRewardPerStake * net);
        _rewardAllUsersStaked(fee);
    }

    function _maybeDistributeMonthlyRewardPool() internal {
        if (monthlyRewardPoolCountdown() == 0 && monthlyRewardPool != 0) {
            uint256 amountToDistribute = (monthlyRewardPool * MONTHLY_POOL_DISTRIBUTE_ALL_USERS_PERCENT) / 100;
            _rewardAllUsersStaked(amountToDistribute);

            _monthlyPoolLastDistributedAt = block.timestamp;
            monthlyRewardPool -= amountToDistribute;
            emit MonthlyRewardPoolDistributed(amountToDistribute);
        }
    }

    function _maybeDistributeBonusRewardPool() internal {
        if (bonusRewardPoolCountdown() == 0 && bonusRewardPool != 0) {
            uint256 amountToDistributeAllUsers = (bonusRewardPool * BONUS_POOL_DISTRIBUTE_ALL_USERS_PERCENT) / 100;
            _rewardAllUsersStaked(amountToDistributeAllUsers);

            uint256 leaderboardUsersCount = _bonusPoolLeaderboardUsersCount();
            uint256 amountToDistributeLeaderboard = (bonusRewardPool * BONUS_POOL_DISTRIBUTE_LEADERBOARD_PERCENT) / 100;
            _bonusPoolTimer = BONUS_POOL_TIMER_INITIAL;  

            _bonusPoolLastDistributedAt = block.timestamp;
            bonusRewardPool -= amountToDistributeAllUsers + amountToDistributeLeaderboard;

            if (leaderboardUsersCount != 0) {
                uint256 amountToDistributePerLeader = amountToDistributeLeaderboard / leaderboardUsersCount;

                if (amountToDistributePerLeader > 0)
                    for (uint256 i = _bonusPoolLeaderboardFirst; i <= _bonusPoolLeaderboardLast; ++i) {
                        require(
                            trustedToken.transfer(_bonusPoolLeaderboard[i], amountToDistributePerLeader),
                            "GreenHouse: bonus transfer"
                        );
                    }
            }

            emit BonusRewardPoolDistributed(amountToDistributeAllUsers, amountToDistributeLeaderboard);
        }
    }
}

pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeCast.sol";

contract GreenHouse is Ownable {

    IERC20 public trustedToken;


    uint256 public allStakes = 0;
    uint256 public everStakedUsersCount = 0;


    uint256 public bonusRewardPool = 0;  
    uint256 public monthlyRewardPool = 0;  
    mapping(address => uint256) public referralRewards;


    mapping(address => uint256) internal _stakes;
    mapping(address => uint256) internal _withdrawals;
    mapping(address => bool) internal _hasStaked;


    uint256 constant internal MAGNITUDE = 2**128;

    uint256 internal _magnifiedRewardPerStake = 0;
    mapping(address => int256) internal _magnifiedRewardCorrections;


    uint256 constant internal FEE_ALL_USERS_STAKED_PERMILLE = 700;
    uint256 constant internal FEE_BONUS_POOL_PERMILLE = 100;
    uint256 constant internal FEE_PLATFORM_WALLET_PERMILLE = 100;
    uint256 constant internal TOKEN_DECIMAL=10**8;
    uint256 constant internal FEE_REFERRAL_PERMILLE = 50;
    uint256 constant internal FEE_PARTNER_WALLET_PERMILLE = 50;


    uint256 constant internal MONTHLY_POOL_DISTRIBUTE_ALL_USERS_PERCENT = 50;
    uint256 constant internal MONYHLY_POOL_TIMER = 86400; 
    uint256 internal _monthlyPoolLastDistributedAt=0;


    uint256 constant internal BONUS_POOL_DISTRIBUTE_ALL_USERS_PERCENT = 40;
    uint256 constant internal BONUS_POOL_DISTRIBUTE_LEADERBOARD_PERCENT = 40;


    mapping(uint256 => address) internal _bonusPoolLeaderboard;
    mapping(address => uint256) internal _bonusPoolLeaderboardPositionsCount;
    uint256 internal _bonusPoolLeaderboardFirst = 1;
    uint256 internal _bonusPoolLeaderboardLast = 0;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MAX_USERS_COUNT = 10;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_QUALIFY = 1000;
    uint256 constant internal BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_MAINTAIN_POSITION = 900; 


uint256 internal _bonusPoolTimer;
uint256 internal _bonusPoolLastDistributedAt=0;
uint256 constant internal BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION = 900;   
    uint256 constant internal BONUS_POOL_TIMER_INITIAL = 21600; 


    address[] internal _platformWallets;

    address   internal _partnerWallet;

    event Staked(address indexed sender, uint256 amount, address indexed referrer);
    event Unstaked(address indexed sender, uint256 amount);
    event RewardWithdrawn(address indexed sender, uint256 amount);
    event BonusRewardPoolDistributed(uint256 amountAllUsers, uint256 amountLeaderboard);
    event MonthlyRewardPoolDistributed(uint256 amount);
    event Timer(uint256 timer);



    constructor(
        address trustedToken_,
        address partnerWallet,
        address[] memory platformWallets
    ) Ownable() {  

        trustedToken = IERC20(trustedToken_);
        _platformWallets = platformWallets;
        _partnerWallet = partnerWallet;
        _bonusPoolTimer = BONUS_POOL_TIMER_INITIAL;
    }

    modifier AttemptToDistrubuteBonusPools() {
        if(_bonusPoolLastDistributedAt == 0 && _monthlyPoolLastDistributedAt== 0){

            _bonusPoolLastDistributedAt = block.timestamp;

            _monthlyPoolLastDistributedAt = block.timestamp;
        }
        _maybeDistributeMonthlyRewardPool();
        _maybeDistributeBonusRewardPool();
        _;
    }



    function stake(uint256 amount, address referrer) external AttemptToDistrubuteBonusPools {
        amount=amount*TOKEN_DECIMAL;
        require(amount != 0, "GreenHouse: staking zero");
        require(
            trustedToken.transferFrom(msg.sender, address(this), amount),
            "GreenHouse: staking transfer"
        );
        require(msg.sender!=referrer,"GreenHouse: You cannot indicate yourself as a referral ");
        if(_stakes[referrer]<100*TOKEN_DECIMAL){
            referrer=address(0);
        }
        if (!_hasStaked[msg.sender]) {
            _hasStaked[msg.sender] = true;
            everStakedUsersCount++;
        }
        if (amount >= BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_QUALIFY*TOKEN_DECIMAL) {
            _bonusPoolProcessStakeholder(msg.sender);
        }

        _processStake(amount, referrer);
        emit Staked(msg.sender, amount, referrer);
    }

    function unstake(uint256 amount) external AttemptToDistrubuteBonusPools {
        amount=amount*TOKEN_DECIMAL;
        require(amount != 0, "GreenHouse: unstaking zero");
        require(_stakes[msg.sender] >= amount, "GreenHouse: unstake amount");

        (uint256 net, uint256 fee) = _applyFeesAndDistributeRewards(amount, address(0));
        _stakes[msg.sender] -= amount;
        _bonusPoolLeaderboardUnstakeToKick(msg.sender, _stakes[msg.sender]);


        _magnifiedRewardCorrections[msg.sender] += SafeCast.toInt256(_magnifiedRewardPerStake * amount);
        _rewardAllUsersStaked(fee);
        allStakes -= amount;

        require(
            trustedToken.transfer(msg.sender, net),
            "GreenHouse: unstake transfer"
        );

        emit Unstaked(msg.sender, amount);
    }

    function withdrawReward() external AttemptToDistrubuteBonusPools {
        uint256 withdrawable = withdrawableRewardOf(msg.sender);
        require(withdrawable > 0, "GreenHouse: nothing to withdraw");
        _withdrawals[msg.sender] += withdrawable;
        require(
            trustedToken.transfer(msg.sender, withdrawable),
            "GreenHouse: withdrawal transfer"
        );
        emit RewardWithdrawn(msg.sender, withdrawable);
    }

    function bonusPoolLeaderboard() external view returns(address[] memory) {
        uint256 leaderboardUsersCount = _bonusPoolLeaderboardUsersCount();
        address[] memory leaderboard = new address[](leaderboardUsersCount);
        uint256 ptr = 0;
        for (uint256 i = _bonusPoolLeaderboardFirst; i <= _bonusPoolLeaderboardLast; i++) {
            leaderboard[ptr] = _bonusPoolLeaderboard[i];
            ptr++;
        }
        return leaderboard;
    }


    function setPartnerWallet(address address_) external onlyOwner {
        _partnerWallet = address_;
    }

    function setPlatformWallets(address[] memory addresses) external onlyOwner {
        _platformWallets = addresses;
    }




    function stakeOf(address stakeholder) public view returns(uint256) {
        return _stakes[stakeholder];
    }

    function accumulativeRewardOf(address stakeholder) public view returns(uint256) {

        return SafeCast.toUint256(
            SafeCast.toInt256(
                stakeOf(stakeholder) * _magnifiedRewardPerStake
            ) + _magnifiedRewardCorrections[stakeholder]
        ) / MAGNITUDE;
    }

    function withdrawnRewardOf(address stakeholder) public view returns(uint256) {
        return _withdrawals[stakeholder];
    }

    function withdrawableRewardOf(address stakeholder) public view returns(uint256) {
        return accumulativeRewardOf(stakeholder) - withdrawnRewardOf(stakeholder);
    }

    function bonusRewardPoolCountdown() public view returns(uint256) {

        uint256 timeSinceLastDistributed = block.timestamp - _bonusPoolLastDistributedAt;
        if (timeSinceLastDistributed >= _bonusPoolTimer) return 0;
        return _bonusPoolTimer - timeSinceLastDistributed;
    }

    function monthlyRewardPoolCountdown() public view returns(uint256) {

        uint256 timeSinceLastDistributed = block.timestamp - _monthlyPoolLastDistributedAt;
        if (timeSinceLastDistributed >= MONYHLY_POOL_TIMER) return 0;
        return MONYHLY_POOL_TIMER - timeSinceLastDistributed;
    }



    function _bonusPoolLeaderboardPop() internal {
        address removed = _bonusPoolLeaderboard[_bonusPoolLeaderboardFirst];
        delete _bonusPoolLeaderboard[_bonusPoolLeaderboardFirst];
        _bonusPoolLeaderboardFirst++;
        _bonusPoolLeaderboardPositionsCount[removed]--;
        if (_bonusPoolLeaderboardPositionsCount[removed] == 0)
            delete _bonusPoolLeaderboardPositionsCount[removed];
    }

    function _bonusPoolLeaderboardPush(address value) internal {
        _bonusPoolLeaderboardLast++;
        _bonusPoolLeaderboard[_bonusPoolLeaderboardLast] = value;
        _bonusPoolLeaderboardPositionsCount[value] += 1;
        if((bonusRewardPoolCountdown()+BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION) >= BONUS_POOL_TIMER_INITIAL){
            _bonusPoolTimer += 0;
        }else{
        _bonusPoolTimer += BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION;
        }
        emit Timer(bonusRewardPoolCountdown()+BONUS_POOL_NEW_STAKEHOLDER_TIME_ADDITION);
    }


    function _bonusPoolProcessStakeholder(address stakeholder) internal {
        _bonusPoolLeaderboardPush(stakeholder);

        if (_bonusPoolLeaderboardUsersCount() > BONUS_POOL_LEADERBOARD_MAX_USERS_COUNT)
            _bonusPoolLeaderboardPop();
    }

    function _bonusPoolLeaderboardKick(address stakeholder, uint256 positions) internal {

        uint256 positionsLeftToKick = positions;
        address[] memory leaderboard = new address[](_bonusPoolLeaderboardUsersCount() - positions);
        uint256 ptr = 0;
        for (
            uint256 i = _bonusPoolLeaderboardFirst;
            i <= _bonusPoolLeaderboardLast;
            i++
        ) {
            if (positionsLeftToKick > 0 && _bonusPoolLeaderboard[i] == stakeholder) {
                positionsLeftToKick--;
            } else {
                leaderboard[ptr] = _bonusPoolLeaderboard[i];
                ptr++;
            }

        }

        while (_bonusPoolLeaderboardUsersCount() > 0)
            _bonusPoolLeaderboardPop();
        for (uint256 i = 0; i < leaderboard.length; ++i)
            _bonusPoolLeaderboardPush(leaderboard[i]);
    }

    function _bonusPoolLeaderboardUnstakeToKick(address stakeholder, uint256 remaining) internal {
        uint256 maxPositions = remaining / BONUS_POOL_LEADERBOARD_MIN_STAKE_TO_MAINTAIN_POSITION;
        if (maxPositions < _bonusPoolLeaderboardPositionsCount[stakeholder]) {
            uint256 positionsToKick = _bonusPoolLeaderboardPositionsCount[stakeholder] - maxPositions;
            _bonusPoolLeaderboardKick(stakeholder, positionsToKick);
        }
    }

    function _bonusPoolLeaderboardUsersCount() internal view returns(uint256) {
        return _bonusPoolLeaderboardLast + 1 - _bonusPoolLeaderboardFirst;
    }

    function _transferRewardPartner(uint256 amount) internal {
        require(
            trustedToken.transfer(_partnerWallet, amount),
            "GreenHouse: partner transfer"
        );
    }

    function _transferRewardPlatform(uint256 amount) internal {
        uint256 perWallet = amount / _platformWallets.length;
        for (uint256 i = 0; i != _platformWallets.length; ++i) {
            require(
                trustedToken.transfer(_platformWallets[i], perWallet),
                "GreenHouse: platform transfer"
            );
        }
    }

    function _rewardAllUsersStaked(uint256 amount) internal {
        _magnifiedRewardPerStake += allStakes != 0 ? (MAGNITUDE * amount) / allStakes : 0;
    }

    function _transferRewardReferral(uint256 amount, address referrer) internal {
        referralRewards[referrer] += amount;
        bool success = trustedToken.transfer(referrer, amount);
        require(success, "GreenHouse: referral transfer");
    }

    function _rewardBonusPool(uint256 amount) internal {
        bonusRewardPool += amount;
    }

    function _rewardMonthlyPool(uint256 amount) internal {
        monthlyRewardPool += amount;
    }

    function _calculateFees(uint256 amount)
    internal pure
    returns(
        uint256 allUsers,
        uint256 bonusPool,
        uint256 partner,
        uint256 referral,
        uint256 platform,
        uint256 net
    ) {
        allUsers = (amount * FEE_ALL_USERS_STAKED_PERMILLE) / 10000;
        bonusPool = (amount * FEE_BONUS_POOL_PERMILLE) / 10000;
        partner = (amount * FEE_PARTNER_WALLET_PERMILLE) / 10000;
        referral = (amount * FEE_REFERRAL_PERMILLE) / 10000;
        platform = (amount * FEE_PLATFORM_WALLET_PERMILLE) / 10000;
        net = amount - allUsers - bonusPool - partner - referral - platform;
    }

    function _applyFeesAndDistributeRewards(uint256 amount, address referrer)
        internal
        returns(uint256, uint256)
    {
        (
            uint256 fee,
            uint256 feeBonusPool,
            uint256 feePartnerWallet,
            uint256 feeReferral,
            uint256 feePlatformWallet,
            uint256 net
        ) = _calculateFees(amount);

        _rewardBonusPool(feeBonusPool);
        _transferRewardPartner(feePartnerWallet);
        _transferRewardPlatform(feePlatformWallet);

        if (referrer == address(0))
            _rewardMonthlyPool(feeReferral);
        else
            _transferRewardReferral(feeReferral, referrer);

        return (net, fee);
    }
    function _processStake(uint256 amount, address referrer) internal {
        (uint256 net, uint256 fee) = _applyFeesAndDistributeRewards(amount, referrer);
        _stakes[msg.sender] += net;

        allStakes += net;

        _magnifiedRewardCorrections[msg.sender] -= SafeCast.toInt256(_magnifiedRewardPerStake * net);
        _rewardAllUsersStaked(fee);
    }

    function _maybeDistributeMonthlyRewardPool() internal {
        if (monthlyRewardPoolCountdown() == 0 && monthlyRewardPool != 0) {
            uint256 amountToDistribute = (monthlyRewardPool * MONTHLY_POOL_DISTRIBUTE_ALL_USERS_PERCENT) / 100;
            _rewardAllUsersStaked(amountToDistribute);

            _monthlyPoolLastDistributedAt = block.timestamp;
            monthlyRewardPool -= amountToDistribute;
            emit MonthlyRewardPoolDistributed(amountToDistribute);
        }
    }

    function _maybeDistributeBonusRewardPool() internal {
        if (bonusRewardPoolCountdown() == 0 && bonusRewardPool != 0) {
            uint256 amountToDistributeAllUsers = (bonusRewardPool * BONUS_POOL_DISTRIBUTE_ALL_USERS_PERCENT) / 100;
            _rewardAllUsersStaked(amountToDistributeAllUsers);

            uint256 leaderboardUsersCount = _bonusPoolLeaderboardUsersCount();
            uint256 amountToDistributeLeaderboard = (bonusRewardPool * BONUS_POOL_DISTRIBUTE_LEADERBOARD_PERCENT) / 100;
            _bonusPoolTimer = BONUS_POOL_TIMER_INITIAL;  

            _bonusPoolLastDistributedAt = block.timestamp;
            bonusRewardPool -= amountToDistributeAllUsers + amountToDistributeLeaderboard;

            if (leaderboardUsersCount != 0) {
                uint256 amountToDistributePerLeader = amountToDistributeLeaderboard / leaderboardUsersCount;

                if (amountToDistributePerLeader > 0)
                    for (uint256 i = _bonusPoolLeaderboardFirst; i <= _bonusPoolLeaderboardLast; ++i) {
                        require(
                            trustedToken.transfer(_bonusPoolLeaderboard[i], amountToDistributePerLeader),
                            "GreenHouse: bonus transfer"
                        );
                    }
            }

            emit BonusRewardPoolDistributed(amountToDistributeAllUsers, amountToDistributeLeaderboard);
        }
    }
}

